using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default renderer changed. Set explicitly to
        // preserve the previous System-rendered appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    // .NET 9 WFO1000: Properties on UserControl must declare serialization
    // configuration via DefaultValueAttribute, DesignerSerializationVisibilityAttribute,
    // or a ShouldSerialize method.
    [DefaultValue("")]
    public string DisplayName { get; set; } = "";

    [DefaultValue(0)]
    public int MaxItems { get; set; }

    /// <summary>
    /// Shows a drop-down editor, guarding against null which is no longer
    /// accepted by IWindowsFormsEditorService.DropDownControl in .NET 9.
    /// </summary>
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control? control)
    {
        if (control is null)
            throw new ArgumentNullException(nameof(control));

        editorService.DropDownControl(control);
    }
}

